interface NavItem {
  label: string;
  icon: React.ReactNode;
  description: string;
  items?: { name: string; desc: string; icon: React.ReactNode }[];
}

const navItems: NavItem[] = [
  {
    label: "Products",
    icon: <Box className="w-5 h-5" />,
