    icon: <Layers className="w-5 h-5" />,
    description: "Industry specific",
    items: [
      { name: "Enterprise", desc: "Scale with confidence", icon: <Box className="w-4 h-4" /> },
      { name: "Startups", desc: "Grow fast, stay lean", icon: <Zap className="w-4 h-4" /> },
